  1→import { router } from "expo-router";
  2→import { LiquidGlassButton, LiquidGlassPopover } from "liquid-glass";
  3→import { Suspense, useCallback, useEffect, useMemo, type JSX } from "react";
  4→import { ErrorBoundary } from "react-error-boundary";
  5→import {
  6→  Keyboard,
  7→  KeyboardAvoidingView,
  8→  Platform,
  9→  Pressable,
 10→  StyleSheet,
 11→  Text,
 12→  View,
 13→} from "react-native";
 14→import Animated from "react-native-reanimated";
 15→import { useSafeAreaInsets } from "react-native-safe-area-context";
 16→import { useDebugContext } from "../features/photo-adjustment/context/DebugContext";
 17→import { EmptyState } from "../features/photos/components/EmptyState";
 18→import { useImportPopover } from "../features/photos/hooks/useImportPopover";
 19→import { usePopoverTransition } from "../features/photos/hooks/usePopoverTransition";
 20→import { AddRecipeButton } from "../features/recipe-form/components/AddRecipeButton";
 21→import { RecipeGrid } from "../features/recipes-list/components/RecipeGrid";
 22→import { useRecipes } from "../features/recipes-list/context/RecipesContext";
 23→import { useGlobalOptions } from "../features/recipes-list/hooks/useGlobalOptions";
 24→import { filterRecipesWithQuery } from "../features/recipes-list/utils/recipeSearch";
 25→import { SearchBar } from "../features/search/components/SearchBar";
 26→import { useAddButtonFocusTransition } from "../features/search/hooks/useAddButtonFocusTransition";
 27→import { useSearchQuery } from "../features/search/hooks/useSearchQuery";
 28→import { useSearchFocus } from "../features/search/hooks/useSearchFocus";
 29→import { useTags } from "../features/tags/context/TagsContext";
 30→import type { RecipeId } from "../lib/types/primitives";
 31→import { useTranslation } from "../platform/i18n/useTranslation";
 32→import { getColors } from "../platform/theme/glassStyles";
 33→import { useTheme } from "../platform/theme/useTheme";
 34→
 35→const HEADER_TOP_GAP = 8;
 36→// NOTE: 61 makes the gap above the three global menu button equal to the gap below
 37→const HEADER_ROW_HEIGHT = 61;
 38→const HEADER_BOTTOM_GAP = 8;
 39→const HEADER_AREA_HEIGHT = HEADER_TOP_GAP + HEADER_ROW_HEIGHT + HEADER_BOTTOM_GAP;
 40→
 41→function ErrorFallback({ error }: { error?: Error }): JSX.Element {
 42→  return (
 43→    <View style={styles.errorContainer}>
 44→      <Text style={styles.errorTitle}>Error loading recipes</Text>
 45→      {error && <Text style={styles.errorMessage}>{error.message}</Text>}
 46→    </View>
 47→  );
 48→}
 49→
 50→function Content(): JSX.Element {
 51→  const theme = useTheme();
 52→  const colors = getColors(theme);
 53→  const { t } = useTranslation();
 54→  const insets = useSafeAreaInsets();
 55→  const { recipes } = useRecipes();
 56→  const { tags, tagLookup } = useTags();
 57→  const {
 58→    query,
 59→    addTagFromSuggestion,
 60→    removeSelectedTag,
 61→    setFreeText,
 62→    clearQuery,
 63→  } = useSearchQuery();
 64→  const filteredRecipes = useMemo(() => {
 65→    return filterRecipesWithQuery(recipes, query, tagLookup);
 66→  }, [recipes, query, tagLookup]);
 67→  const { handleFocus, handleBlur, key, isFocused } = useSearchFocus();
 68→  const { setDebugData } = useDebugContext();
 69→
 70→  const {
 71→    showPopover,
 72→    popoverVisible,
 73→    dismissPopover,
 74→    isImporting,
 75→    importOptions,
 76→    handleImportOptionSelect,
 77→  } = useImportPopover();
 78→  const shouldHideSearchBar = popoverVisible || isImporting;
 79→  const { buttonStyle } = usePopoverTransition(shouldHideSearchBar);
 80→
 81→  const globalOptions = useGlobalOptions();
 82→  const { addButtonOuterStyle, addButtonInnerStyle } =
 83→    useAddButtonFocusTransition(isFocused);
 84→
 85→  useEffect(() => {
 86→    return () => {
 87→      setDebugData(null);
 88→    };
 89→  }, [setDebugData]);
 90→
 91→  const isAddButtonInteractive = !isFocused && !popoverVisible && !isImporting;
 92→
 93→  const dismissSearchFocus = useCallback((): void => {
 94→    if (!isFocused) {
 95→      return;
 96→    }
 97→
 98→    handleBlur();
 99→    Keyboard.dismiss();
100→  }, [handleBlur, isFocused]);
101→
102→  const handleRecipeTap = useCallback(
103→    (id: RecipeId): void => {
104→      dismissSearchFocus();
105→      router.push(`/recipe/${id}`);
106→    },
107→    [dismissSearchFocus]
108→  );
109→
110→  const handleGlobalMenuPress = useCallback((): void => {
111→    dismissSearchFocus();
112→    globalOptions.handlePress();
113→  }, [dismissSearchFocus, globalOptions]);
114→
115→  return (
116→    <View style={[styles.container, { backgroundColor: colors.background }]}>
117→      {recipes.length === 0 ? (
118→        <Pressable style={styles.container} onPress={dismissSearchFocus}>
119→          <EmptyState onAddPress={showPopover} />
120→        </Pressable>
121→      ) : (
122→        <RecipeGrid
123→          recipes={filteredRecipes}
124→          onRecipeTap={handleRecipeTap}
125→          headerInset={HEADER_AREA_HEIGHT}
126→          onSurfaceTouchStart={dismissSearchFocus}
127→        />
128→      )}
129→
130→      {/* Header row - title + overflow menu button */}
131→      <Animated.View
132→        style={[
133→          styles.headerRow,
134→          { top: insets.top + HEADER_TOP_GAP },
135→          globalOptions.buttonStyle,
136→        ]}
137→        pointerEvents={popoverVisible || globalOptions.visible ? "none" : "auto"}
138→      >
139→        <Pressable onPress={dismissSearchFocus} style={styles.headerTitleTouchArea}>
140→          <Text style={[styles.headerTitle, { color: colors.text }]}>
141→            {t("library.heading")}
142→          </Text>
143→        </Pressable>
144→        <LiquidGlassButton
145→          onPress={handleGlobalMenuPress}
146→          systemImage="ellipsis"
147→          accessibilityLabel={t("accessibility.moreOptions")}
148→        />
149→      </Animated.View>
150→
151→      {recipes.length > 0 && (
152→        <KeyboardAvoidingView
153→          behavior={Platform.OS === "ios" ? "padding" : "height"}
154→          style={styles.keyboardAvoid}
155→        >
156→          <View style={styles.bottomBar}>
157→            <View style={styles.searchBarWrapper}>
158→              <SearchBar
159→                key={key}
160→                selectedTags={query.selectedTags}
161→                freeText={query.freeText}
162→                suggestionPrefix={query.suggestionPrefix}
163→                allTags={tags}
164→                onChangeFreeText={setFreeText}
165→                onAddTagFromSuggestion={addTagFromSuggestion}
166→                onRemoveSelectedTag={removeSelectedTag}
167→                onClearQuery={clearQuery}
168→                onFocus={handleFocus}
169→                onBlur={handleBlur}
170→                blocked={shouldHideSearchBar}
171→                isFocused={isFocused}
172→              />
173→            </View>
174→            <Animated.View
175→              style={[styles.addButtonOuterWrapper, buttonStyle, addButtonOuterStyle]}
176→            >
177→              <Animated.View
178→                style={[styles.addButtonWrapper, addButtonInnerStyle]}
179→                pointerEvents={isAddButtonInteractive ? "auto" : "none"}
180→              >
181→                <AddRecipeButton onPress={showPopover} />
182→              </Animated.View>
183→            </Animated.View>
184→          </View>
185→        </KeyboardAvoidingView>
186→      )}
187→
188→      {/* Import popover */}
189→      <View
190→        style={[
191→          StyleSheet.absoluteFill,
192→          styles.popoverLayer,
193→          !popoverVisible && isImporting && { opacity: 0 },
194→        ]}
195→        pointerEvents={popoverVisible ? "auto" : "none"}
196→      >
197→        <LiquidGlassPopover
198→          visible={popoverVisible}
199→          options={importOptions}
200→          buttonSize={56}
201→          anchor={recipes.length === 0 ? "center" : undefined}
202→          onSelect={handleImportOptionSelect}
203→          onDismiss={dismissPopover}
204→        />
205→      </View>
206→
207→      {/* Overflow popover (top trailing) */}
208→      <View
209→        style={[StyleSheet.absoluteFill, styles.popoverLayer]}
210→        pointerEvents={globalOptions.visible ? "auto" : "none"}
211→      >
212→        <LiquidGlassPopover
213→          visible={globalOptions.visible}
214→          anchor="topTrailing"
215→          buttonOffset={{ x: 28, y: insets.top + HEADER_TOP_GAP }}
216→          options={globalOptions.options}
217→          buttonSize={48}
218→          onSelect={globalOptions.handleSelect}
219→          onDismiss={globalOptions.handleDismiss}
220→        />
221→      </View>
222→    </View>
223→  );
224→}
225→
226→export default function Index(): JSX.Element {
227→  return (
228→    <ErrorBoundary FallbackComponent={ErrorFallback}>
229→      <Suspense fallback={<View style={styles.suspenseFallback} />}>
230→        <Content />
231→      </Suspense>
232→    </ErrorBoundary>
233→  );
234→}
235→
236→const styles = StyleSheet.create({
237→  addButtonOuterWrapper: {
238→    justifyContent: "center",
239→  },
240→  addButtonWrapper: {
241→    justifyContent: "center",
242→    alignItems: "center",
243→  },
244→  container: {
245→    flex: 1,
246→  },
247→  headerRow: {
248→    position: "absolute",
249→    left: 28,
250→    right: 28,
251→    flexDirection: "row",
252→    alignItems: "center",
253→    justifyContent: "space-between",
254→    zIndex: 10,
255→    height: 48,
256→  },
257→  headerTitle: {
258→    fontSize: 32,
259→    fontWeight: "bold",
260→  },
261→  headerTitleTouchArea: {
262→    paddingRight: 12,
263→  },
264→  popoverLayer: {
265→    zIndex: 11,
266→  },
267→  keyboardAvoid: {
268→    position: "absolute",
269→    bottom: 0,
270→    left: 0,
271→    right: 0,
272→    zIndex: 10,
273→  },
274→  bottomBar: {
275→    flexDirection: "row",
276→    // NOTE: The same effective space from the screen to button edges for the `Add note` button in the Apple Notes app
277→    paddingHorizontal: 28,
278→    paddingBottom: 28,
279→  },
280→  searchBarWrapper: {
281→    flex: 1,
282→  },
283→  suspenseFallback: {
284→    flex: 1,
285→  },
286→  errorContainer: {
287→    flex: 1,
288→    justifyContent: "center",
289→    alignItems: "center",
290→    padding: 20,
